export const AUTH_SYSTEM_INFO = {
    hashingAlgorithm: 'SHA-256 (Web Crypto API)',
    hashingStrategy: 'Salt + Password + Server Pepper',
    sessionStrategy: 'Bearer Token (Simulated HttpOnly)',
    sessionSecurity: 'User-Agent Binding + Idle Timeout',
    compliance: ['GDPR Data Export', 'Right to be Forgotten', 'OWASP Auth Standards']
};

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

// --- Helper: Crypto Simulation (Async for realism) ---
const sha256 = async (str: string) => {
    const encoder = new TextEncoder();
    const data = encoder.encode(str);
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

const hashPassword = async (password: string, salt: string) => {
    // Simulating robust hashing (e.g. Argon2) by mixing salt, password and server pepper
    return await sha256(`${salt}:${password}:${SERVER_PEPPER}`);
};

const hashToken = async (token: string) => {
    // Simulating HMAC-SHA256
    return await sha256(`${SERVER_PEPPER}:${token}`);
};

const generateSalt = () => {
    const array = new Uint8Array(16);
    crypto.getRandomValues(array);
    return Array.from(array).map(b => b.toString(16).padStart(2, '0')).join('');
};

const generateToken = () => {
    // Generate 32 bytes of random data, converted to hex (64 chars)
    const array = new Uint8Array(32);
    crypto.getRandomValues(array);
    return Array.from(array).map(b => b.toString(16).padStart(2, '0')).join('');
};

// --- Helper: DB Access ---
const getTable = <T>(key: string): T[] => {
    try { return JSON.parse(localStorage.getItem(key) || '[]'); } 
    catch { return []; }
};
const saveTable = (key: string, data: any[]) => localStorage.setItem(key, JSON.stringify(data));

// --- Helper: Logging ---
const logActivity = (
    userId: string, 
    action: ActivityLogItem['action'], 
    status: ActivityLogItem['status'] = 'SUCCESS', 
    details?: string
) => {
    const logs = getTable<ActivityLogItem>(DB_LOGS);
    const newLog: ActivityLogItem = {
        id: crypto.randomUUID(),
        userId,
        action,
        status,
        details,
        ip: '192.168.1.X', // Simulated IP
        userAgent: navigator.userAgent,
        timestamp: Date.now()
    };
    // Keep last 1000 logs
    const updatedLogs = [newLog, ...logs].slice(0, 1000);
    saveTable(DB_LOGS, updatedLogs);
};

// --- Mapper ---
const mapDBUserToUser = (dbUser: DBUser): User => ({
    id: dbUser.id,
    username: dbUser.username,
    email: dbUser.email,
    isVerified: dbUser.email_verified,
    createdAt: dbUser.created_at,
    avatar: dbUser.avatar_url,
    settings: JSON.parse(dbUser.settings_json),
    failedLoginAttempts: dbUser.failed_login_attempts,
    lockoutUntil: dbUser.lockout_until
});

// Rate limiter for specific actions
const checkRateLimit = (key: string, limit: number, windowMs: number): boolean => {
    const storageKey = `ratelimit_${key}`;
    const now = Date.now();
    const record = JSON.parse(localStorage.getItem(storageKey) || '{"count": 0, "startTime": 0}');

    if (now - record.startTime > windowMs) {
        // Reset window
        localStorage.setItem(storageKey, JSON.stringify({ count: 1, startTime: now }));
        return true;
    }

    if (record.count >= limit) {
        return false;
    }

    record.count += 1;
    localStorage.setItem(storageKey, JSON.stringify(record));
    return true;
};


export const authService = {

    getSession: async (): Promise<User | null> => {
        const sessionToken = localStorage.getItem('studygenius_session_token');
        if (!sessionToken) return null;

        const sessions = getTable<DBSession>(DB_SESSIONS);
        const users = getTable<DBUser>(DB_USERS);

        const tokenHash = await hashToken(sessionToken);

        // Find session
        const sessionIndex = sessions.findIndex(s => s.token_hash === tokenHash);
        if (sessionIndex === -1) {
            localStorage.removeItem('studygenius_session_token');
            return null;
        }

        const session = sessions[sessionIndex];

        // 1. Check Expiry
        if (session.expires_at < Date.now()) {
             localStorage.removeItem('studygenius_session_token');
             sessions.splice(sessionIndex, 1);
             saveTable(DB_SESSIONS, sessions);
             return null;
        }

        // 2. Enhanced Security: User-Agent Binding (Step 19)
        // If the browser signature changes, invalidate the session to prevent hijacking
        if (session.user_agent && session.user_agent !== navigator.userAgent) {
             console.warn("[Security] Session hijacked or browser changed. Invalidating.");
             localStorage.removeItem('studygenius_session_token');
             sessions.splice(sessionIndex, 1);
             saveTable(DB_SESSIONS, sessions);
             return null;
        }

        // Update Last Used At (Session activity tracking)
        session.last_used_at = Date.now();
        sessions[sessionIndex] = session;
        saveTable(DB_SESSIONS, sessions);

        const user = users.find(u => u.id === session.user_id);
        return user ? mapDBUserToUser(user) : null;
    },

    getUserSessions: async (userId: string): Promise<UserSession[]> => {
        const sessions = getTable<DBSession>(DB_SESSIONS);
        const currentToken = localStorage.getItem('studygenius_session_token');
        let currentTokenHash = '';
        if (currentToken) {
            currentTokenHash = await hashToken(currentToken);
        }

        return sessions
            .filter(s => s.user_id === userId)
            .map(s => ({
                id: s.id,
                userAgent: s.user_agent || 'Unknown Device',
                lastUsedAt: s.last_used_at,
                createdAt: s.created_at,
                isCurrent: s.token_hash === currentTokenHash
            }))
            .sort((a, b) => b.lastUsedAt - a.lastUsedAt);
    },

