        const session = sessions.find(s => s.id === sessionId);
        if (session) {
             const newSessions = sessions.filter(s => s.id !== sessionId);
             saveTable(DB_SESSIONS, newSessions);
             logActivity(session.user_id, 'LOGOUT', 'SUCCESS', 'Remote session revocation');
