    /**
     * Log in with Rate Limiting & Hashing & Verification Check & MFA
     */
    login: async (emailOrUsername: string, password: string): Promise<LoginResult> => {
        await delay(800);
        const users = getTable<DBUser>(DB_USERS);
        const normalizedInput = emailOrUsername.toLowerCase();

        const userIndex = users.findIndex(u => 
            u.email.toLowerCase() === normalizedInput || u.username.toLowerCase() === normalizedInput
        );

        if (userIndex === -1) throw new Error("Invalid credentials");

        const user = users[userIndex];

        // 1. Check Lockout
        if (user.lockout_until && user.lockout_until > Date.now()) {
            logActivity(user.id, 'LOGIN_FAILED', 'FAILURE', 'Attempt during lockout period');
            throw new Error(`Account locked. Try again in ${Math.ceil((user.lockout_until - Date.now()) / 60000)} minutes.`);
        }

        // 2. Verify Password
        if (!user.password_hash || !user.password_salt) {
            throw new Error("Please sign in using your social account.");
        }

        const hash = await hashPassword(password, user.password_salt);
        if (hash !== user.password_hash) {
            // Increment failure count
            user.failed_login_attempts = (user.failed_login_attempts || 0) + 1;

            let logDetails = 'Invalid password';
            // Lockout policy: 5 attempts -> 15 min lockout
            if (user.failed_login_attempts >= 5) {
                user.lockout_until = Date.now() + 15 * 60 * 1000;
                user.failed_login_attempts = 0;
                logDetails = 'Account Locked due to 5 failed attempts';
                logActivity(user.id, 'ACCOUNT_LOCKED', 'WARNING', 'Brute force protection triggered');
            }

            users[userIndex] = user;
            saveTable(DB_USERS, users);
            logActivity(user.id, 'LOGIN_FAILED', 'FAILURE', logDetails);
            throw new Error("Invalid credentials");
        }

        // 3. Check Email Verification
        if (!user.email_verified) {
            logActivity(user.id, 'LOGIN_FAILED', 'FAILURE', 'Email not verified');
            throw new Error("Please verify your email address before logging in.");
        }

        // 4. Success: Reset security counters
        user.failed_login_attempts = 0;
        user.lockout_until = undefined;
        users[userIndex] = user;
        saveTable(DB_USERS, users);

        // 5. MFA Check
        const settings = JSON.parse(user.settings_json);
        if (settings.mfaEnabled) {
            // Generate a temporary MFA token (could store this in DB, but simplifying for mock)
            const tempToken = `mfa_temp_${generateToken()}`; 
            // In real app, send 2FA code via email/SMS here
            console.log(`[MFA] Code for ${user.username}: 123456`); // Mock code
            return { mfaRequired: true, tempToken, user: mapDBUserToUser(user) };
        }

        logActivity(user.id, 'LOGIN_SUCCESS', 'SUCCESS', 'Standard login');
        const loggedInUser = await authService.createSession(user.id);
        return { user: loggedInUser };
    },

