    resetPassword: async (token: string, newPassword: string): Promise<void> => {
        await delay(1000);
        const dbTokens = getTable<DBResetToken>(DB_TOKENS);
        const tokenHash = await hashToken(token); // Verify against hash
        const tokenIdx = dbTokens.findIndex(t => t.token_hash === tokenHash);

        if (tokenIdx === -1) throw new Error("Invalid or expired token");
        const tokenRecord = dbTokens[tokenIdx];

        if (tokenRecord.used) throw new Error("Token already used");
        if (tokenRecord.expires_at < Date.now()) throw new Error("Token expired");

        // Update User
        const users = getTable<DBUser>(DB_USERS);
        const userIdx = users.findIndex(u => u.id === tokenRecord.user_id);
        if (userIdx === -1) throw new Error("User not found");

        const user = users[userIdx];
        const newSalt = generateSalt();
        user.password_salt = newSalt;
        user.password_hash = await hashPassword(newPassword, newSalt);
        user.updated_at = Date.now();
        user.failed_login_attempts = 0; 
        user.lockout_until = undefined;

        users[userIdx] = user;
        saveTable(DB_USERS, users);

        // Mark Token Used
        tokenRecord.used = true;
        dbTokens[tokenIdx] = tokenRecord;
        saveTable(DB_TOKENS, dbTokens);

        // Security: Invalidate ALL sessions for this user (Session Revocation)
        const sessions = getTable<DBSession>(DB_SESSIONS);
        const activeSessions = sessions.filter(s => s.user_id !== user.id);
        saveTable(DB_SESSIONS, activeSessions);

        logActivity(user.id, 'PASSWORD_CHANGE', 'SUCCESS', 'Via reset token');
    },

