  // Renderers
  if (step === 'upload' || step === 'generating') {
    return (
      <div className="max-w-5xl mx-auto px-4 py-12">
        <Header title="Create New Quiz" onBack={onBack} />

        <div className="grid md:grid-cols-12 gap-8">
