const DB_LOGS = 'studygenius_db_logs'; // Security Audit Logs

// Simulated Server Secret for HMAC-like hashing
const SERVER_PEPPER = 'studygenius_secure_server_pepper_v1';

// --- System Architecture Info ---
export const AUTH_SYSTEM_INFO = {
    hashingAlgorithm: 'SHA-256 (Web Crypto API)',
    hashingStrategy: 'Salt + Password + Server Pepper',
    sessionStrategy: 'Bearer Token (Simulated HttpOnly)',
    sessionSecurity: 'User-Agent Binding + Idle Timeout',
    compliance: ['GDPR Data Export', 'Right to be Forgotten', 'OWASP Auth Standards']
};

// OPTIMIZED: Reduced delay for snappier UI response (Max 400ms)
const delay = (ms: number) => new Promise(res => setTimeout(res, Math.min(ms, 400)));

// --- Helper: Crypto Simulation (Async for realism) ---
const sha256 = async (str: string) => {
    const encoder = new TextEncoder();
    const data = encoder.encode(str);
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

const hashPassword = async (password: string, salt: string) => {
    // Simulating robust hashing (e.g. Argon2) by mixing salt, password and server pepper
    return await sha256(`${salt}:${password}:${SERVER_PEPPER}`);
};

const hashToken = async (token: string) => {
    // Simulating HMAC-SHA256
    return await sha256(`${SERVER_PEPPER}:${token}`);
};

const generateSalt = () => {
    const array = new Uint8Array(16);
    crypto.getRandomValues(array);
    return Array.from(array).map(b => b.toString(16).padStart(2, '0')).join('');
};

const generateToken = () => {
    // Generate 32 bytes of random data, converted to hex (64 chars)
    const array = new Uint8Array(32);
    crypto.getRandomValues(array);
    return Array.from(array).map(b => b.toString(16).padStart(2, '0')).join('');
};

// --- Helper: DB Access ---
const getTable = <T>(key: string): T[] => {
    try { return JSON.parse(localStorage.getItem(key) || '[]'); } 
    catch { return []; }
};
const saveTable = (key: string, data: any[]) => localStorage.setItem(key, JSON.stringify(data));

