};

// --- Mapper ---
const mapDBUserToUser = (dbUser: DBUser): User => ({
    id: dbUser.id,
    username: dbUser.username || 'User', // Fallback to prevent undefined crashes
    email: dbUser.email,
    isVerified: dbUser.email_verified,
