    avatar: dbUser.avatar_url,
    settings: JSON.parse(dbUser.settings_json),
    failedLoginAttempts: dbUser.failed_login_attempts,
    lockoutUntil: dbUser.lockout_until
});

// Rate limiter for specific actions
const checkRateLimit = (key: string, limit: number, windowMs: number): boolean => {
    const storageKey = `ratelimit_${key}`;
    const now = Date.now();
    const record = JSON.parse(localStorage.getItem(storageKey) || '{"count": 0, "startTime": 0}');

    if (now - record.startTime > windowMs) {
        // Reset window
        localStorage.setItem(storageKey, JSON.stringify({ count: 1, startTime: now }));
        return true;
    }

    if (record.count >= limit) {
        return false;
    }

    record.count += 1;
    localStorage.setItem(storageKey, JSON.stringify(record));
    return true;
};


