             user.password_salt = salt;
             user.password_hash = await hashPassword(updates.password, salt);
             logActivity(userId, 'PASSWORD_CHANGE', 'SUCCESS', 'Profile update');
        }
        if (updates.settings) {
             user.settings_json = JSON.stringify({ ...settings, ...updates.settings });
             if (updates.settings.mfaEnabled !== settings.mfaEnabled) {
                 logActivity(userId, 'MFA_VERIFY', 'SUCCESS', `MFA ${updates.settings.mfaEnabled ? 'Enabled' : 'Disabled'}`);
             }
        }

        users[idx] = user;
        saveTable(DB_USERS, users);
        return mapDBUserToUser(user);
    },

    getLinkedAccounts: (userId: string): DBOAuthAccount[] => {
        const accounts = getTable<DBOAuthAccount>(DB_OAUTH);
        return accounts.filter(a => a.user_id === userId);
    },

    linkSocialAccount: async (userId: string, provider: 'google' | 'facebook'): Promise<void> => {
        await delay(400);
        const accounts = getTable<DBOAuthAccount>(DB_OAUTH);
        if (accounts.some(a => a.user_id === userId && a.provider === provider)) return;

        accounts.push({
            id: crypto.randomUUID(),
            user_id: userId,
            provider,
            provider_user_id: `pid_linked_${Date.now()}`,
            provider_email: `linked_${provider}@example.com`,
            created_at: Date.now()
        });
        saveTable(DB_OAUTH, accounts);
        logActivity(userId, 'ACCOUNT_LINK', 'SUCCESS', provider);
    },

    unlinkSocialAccount: async (userId: string, provider: 'google' | 'facebook'): Promise<void> => {
        await delay(300);
        const accounts = getTable<DBOAuthAccount>(DB_OAUTH);
        const newAccounts = accounts.filter(a => !(a.user_id === userId && a.provider === provider));
        saveTable(DB_OAUTH, newAccounts);
        logActivity(userId, 'ACCOUNT_UNLINK', 'SUCCESS', provider);
    },

    getUserActivity: async (userId: string): Promise<ActivityLogItem[]> => {
        const logs = getTable<ActivityLogItem>(DB_LOGS);
        return logs.filter(l => l.userId === userId).sort((a, b) => b.timestamp - a.timestamp);
    },

    // --- Privacy & Compliance ---

    exportUserData: async (userId: string): Promise<string> => {
        await delay(500);
        const users = getTable<DBUser>(DB_USERS);
        const user = users.find(u => u.id === userId);
        if (!user) throw new Error("User not found");

        const oauth = getTable<DBOAuthAccount>(DB_OAUTH).filter(a => a.user_id === userId);
        const sessions = getTable<DBSession>(DB_SESSIONS).filter(s => s.user_id === userId);
        const activity = getTable<ActivityLogItem>(DB_LOGS).filter(l => l.userId === userId);

        // Get History Data
        const historyKey = `studygenius_history_${userId}`;
        let history = [];
        try {
            history = JSON.parse(localStorage.getItem(historyKey) || '[]');
        } catch (e) {}

        const exportData = {
            userProfile: mapDBUserToUser(user),
            rawUserData: user,
            linkedAccounts: oauth,
            activeSessions: sessions,
            securityLogs: activity,
            activityHistory: history,
            exportDate: new Date().toISOString(),
            metadata: {
                appName: "StudyGenius AI",
                version: "1.0.0"
            }
        };

        logActivity(userId, 'DATA_EXPORT', 'SUCCESS');
        return JSON.stringify(exportData, null, 2);
    },

    deleteAccount: async (userId: string): Promise<void> => {
        await delay(1000);

        // 1. Delete User
        const users = getTable<DBUser>(DB_USERS);
        const newUsers = users.filter(u => u.id !== userId);
        saveTable(DB_USERS, newUsers);

        // 2. Delete OAuth
        const oauth = getTable<DBOAuthAccount>(DB_OAUTH);
        const newOAuth = oauth.filter(a => a.user_id !== userId);
        saveTable(DB_OAUTH, newOAuth);

        // 3. Delete Sessions
        const sessions = getTable<DBSession>(DB_SESSIONS);
        const newSessions = sessions.filter(s => s.user_id !== userId);
        saveTable(DB_SESSIONS, newSessions);

        // 4. Delete Tokens
        const tokens = getTable<DBResetToken>(DB_TOKENS);
        const newTokens = tokens.filter(t => t.user_id !== userId);
        saveTable(DB_TOKENS, newTokens);

        const verifications = getTable<DBVerificationToken>(DB_VERIFICATIONS);
        const newVerifications = verifications.filter(v => v.user_id !== userId);
        saveTable(DB_VERIFICATIONS, newVerifications);

        // 5. Delete Logs
        const logs = getTable<ActivityLogItem>(DB_LOGS);
        const newLogs = logs.filter(l => l.userId !== userId);
        saveTable(DB_LOGS, newLogs);

        // 6. Delete History
        localStorage.removeItem(`studygenius_history_${userId}`);
    }
};
