// --- Helpers ---

const generateFilename = (type: string, title: string, ext: string): string => {
    const safeTitle = title.replace(/[^a-z0-9]/gi, '_').substring(0, 30);
    const date = new Date().toISOString().split('T')[0].replace(/-/g, '');
    const id = Math.random().toString(36).substring(2, 6);
    return `StudyGenius_${type}_${safeTitle}_${date}_${id}.${ext}`;
};

const setPDFMetadata = (doc: any, title: string) => {
    doc.setProperties({
        title: title,
        subject: 'Study Material',
        author: 'StudyGenius AI User',
        keywords: 'quiz, summary, study aid, ai',
        creator: 'StudyGenius AI'
    });
};

const addPDFFooter = (doc: any, sourceFile: string) => {
    const pageCount = doc.internal.getNumberOfPages();
    const width = doc.internal.pageSize.getWidth();
    const height = doc.internal.pageSize.getHeight();

    doc.setFontSize(8);
    doc.setTextColor(150);

    for(let i = 1; i <= pageCount; i++) {
        doc.setPage(i);
        const footer = `Generated by StudyGenius AI • ${new Date().toLocaleString()} • Source: ${sourceFile}`;
        doc.text(footer, 10, height - 10);
        doc.text(`Page ${i} of ${pageCount}`, width - 25, height - 10);
    }
};

export const extractTextFromFile = async (file: File): Promise<string> => {
  const fileType = file.type;

  if (fileType === 'application/pdf') {
    return extractPdfText(file);
  } else if (fileType.startsWith('text/') || file.name.endsWith('.txt') || file.name.endsWith('.md')) {
    return await file.text();
  } else {
    throw new Error('Unsupported file type for text extraction. Please upload a PDF or Text file.');
  }
};

const extractPdfText = async (file: File): Promise<string> => {
  if (!window.pdfjsLib) {
    throw new Error('PDF.js library not loaded');
  }

  window.pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

  const arrayBuffer = await file.arrayBuffer();
  const pdf = await window.pdfjsLib.getDocument({ data: arrayBuffer }).promise;

  let fullText = '';
  const maxPages = pdf.numPages;

  for (let i = 1; i <= maxPages; i++) {
    const page = await pdf.getPage(i);
    const textContent = await page.getTextContent();
    const pageText = textContent.items.map((item: any) => item.str).join(' ');
    fullText += `\n\n--- Page ${i} ---\n\n${pageText}`;
  }

  return fullText;
};

