        // Client-side immediate
        if (format === 'pdf' || format === 'csv') {
            return { file: new Blob([''], { type: 'application/pdf' }) }; // Placeholder, handled by sync functions below
        }

        // Server-side simulation
        return new Promise((resolve) => {
            setTimeout(() => {
                resolve({ jobId: `job_${Date.now()}_${format}` });
            }, 1000);
        });
    },

    checkExportStatus: async (jobId: string): Promise<'pending' | 'completed' | 'failed'> => {
        // Randomly finish after a few polls
        return new Promise(resolve => {
            setTimeout(() => {
                const r = Math.random();
                resolve(r > 0.7 ? 'completed' : 'pending');
            }, 800);
        });
    },

    getDownloadUrl: (jobId: string) => {
        return `https://studygenius.ai/api/download/${jobId}`; // Mock URL
    }
};

