export const generatePDF = (title: string, content: string) => {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();
    setPDFMetadata(doc, title);

    const pageWidth = doc.internal.pageSize.getWidth();
    const margin = 10;
    const maxLineWidth = pageWidth - (margin * 2);

