export const downloadQuizPDF = (
    quiz: Quiz, 
    options: { includeAnswers: boolean, includeExplanations: boolean, includeScore: boolean },
    userAnswers?: Record<string, string>
) => {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();
    setPDFMetadata(doc, quiz.title);

    const margin = 15;
    let y = 20;
    const pageWidth = doc.internal.pageSize.getWidth();
    const contentWidth = pageWidth - (margin * 2);
    const pageHeight = doc.internal.pageSize.getHeight();

    const addNewPageIfNeeded = (heightNeeded: number = 20) => {
        if (y + heightNeeded > pageHeight - margin - 10) {
            doc.addPage();
            y = 20;
        }
    };

    // Header
    doc.setFontSize(18);
    doc.setFont("helvetica", "bold");
    doc.text(quiz.title, margin, y);
    y += 10;

    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(100);

    let modeLabel = 'Study Material';
    if (options.includeAnswers) modeLabel = 'Answer Key';
    else if (options.includeScore) modeLabel = 'Results Report';
    else modeLabel = 'Student Copy';

    let sub = `Generated by StudyGenius AI • ${modeLabel}`;
    if (quiz.topic) sub += ` • Topic: ${quiz.topic}`;
    doc.text(sub, margin, y);
    y += 15;

    if (options.includeScore && quiz.score !== undefined) {
        doc.setFontSize(14);
        doc.setTextColor(0);
        doc.text(`Final Score: ${quiz.score} / ${quiz.questions.length}`, margin, y);
        y += 15;
    }

    // Questions
    quiz.questions.forEach((q, i) => {
        addNewPageIfNeeded(40); 

        doc.setFontSize(11);
        doc.setTextColor(0);
        doc.setFont("helvetica", "bold");
        const qText = `${i + 1}. ${q.text}`;
        const splitQ = doc.splitTextToSize(qText, contentWidth);
        doc.text(splitQ, margin, y);
        y += (splitQ.length * 6) + 4;

        doc.setFont("helvetica", "normal");
        doc.setFontSize(10);

        q.options.forEach((opt) => {
            addNewPageIfNeeded(10);
            let prefix = "○"; 
            let optColor = [60, 60, 60]; 

            if (options.includeAnswers && !options.includeScore) { // Teacher Key
                if (opt === q.correctAnswer) {
                    prefix = "●"; 
                    doc.setFont("helvetica", "bold");
                    optColor = [0, 128, 0]; 
                } else {
                    doc.setFont("helvetica", "normal");
                }
            } else if (options.includeScore && userAnswers) { // Results
                const userAnswer = userAnswers[q.id];
                if (opt === q.correctAnswer) {
                    prefix = "✓";
                    optColor = [0, 128, 0];
                } else if (opt === userAnswer && userAnswer !== q.correctAnswer) {
                    prefix = "✗";
                    optColor = [200, 0, 0];
                } else if (opt === userAnswer) {
                    prefix = "●"; 
                }
            }

            doc.setTextColor(optColor[0], optColor[1], optColor[2]);
            const optText = `${prefix} ${opt}`;
            const splitOpt = doc.splitTextToSize(optText, contentWidth - 5);
            doc.text(splitOpt, margin + 5, y);
            y += (splitOpt.length * 5) + 2;
        });

        // Explanations
        if (options.includeExplanations) {
            addNewPageIfNeeded(20);
            y += 2;
            doc.setFillColor(245, 247, 250);
            const explLines = doc.splitTextToSize(q.explanation, contentWidth - 10);
            doc.roundedRect(margin, y, contentWidth, 15 + (explLines.length * 4), 2, 2, 'F');

            doc.setTextColor(80);
            doc.setFontSize(9);
            doc.setFont("helvetica", "italic");
            doc.text("Explanation:", margin + 3, y + 6);

            doc.setTextColor(50);
            doc.setFont("helvetica", "normal");
            doc.text(explLines, margin + 3, y + 11);

            y += 15 + (explLines.length * 4) + 10;
        } else {
            y += 8;
        }
    });

    addPDFFooter(doc, quiz.sourceFileName);
    const suffix = options.includeAnswers ? 'key' : options.includeScore ? 'result' : 'test';
    const filename = generateFilename('quiz', `${quiz.title}_${suffix}`, 'pdf');
    doc.save(filename);
};

