import { Flashcard, Quiz, Summary, SmartNote, ComparisonTable, MindMapNode } from '../types';

// Global types for libraries loaded via CDN
declare global {
    interface Window {
        JSZip: any;
        saveAs: any; // FileSaver.js
        jspdf: any;
    }
}

export const extractTextFromFile = async (file: File): Promise<string> => {
  const fileType = file.type;

  if (fileType === 'application/pdf') {
    return extractPdfText(file);
  } else if (fileType.startsWith('text/') || file.name.endsWith('.txt') || file.name.endsWith('.md')) {
    return await file.text();
  } else {
    throw new Error('Unsupported file type for text extraction. Please upload a PDF or Text file.');
  }
};

const extractPdfText = async (file: File): Promise<string> => {
  if (!window.pdfjsLib) {
    throw new Error('PDF.js library not loaded');
  }

  window.pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

  const arrayBuffer = await file.arrayBuffer();
  const pdf = await window.pdfjsLib.getDocument({ data: arrayBuffer }).promise;

  let fullText = '';
  const maxPages = pdf.numPages;

  for (let i = 1; i <= maxPages; i++) {
    const page = await pdf.getPage(i);
    const textContent = await page.getTextContent();
    const pageText = textContent.items.map((item: any) => item.str).join(' ');
    fullText += `\n\n--- Page ${i} ---\n\n${pageText}`;
  }

  return fullText;
};

