};

export const generatePDF = (title: string, content: string) => {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();

    const pageWidth = doc.internal.pageSize.getWidth();
    const margin = 10;
    const maxLineWidth = pageWidth - (margin * 2);

    doc.setFontSize(16);
    doc.text(title, margin, 20);

    doc.setFontSize(12);
    const splitText = doc.splitTextToSize(content, maxLineWidth);

    let y = 30;
    const pageHeight = doc.internal.pageSize.getHeight();
    const lineHeight = 7;

    splitText.forEach((line: string) => {
        if (y + lineHeight > pageHeight - margin) {
            doc.addPage();
            y = 20;
        }
        doc.text(line, margin, y);
        y += lineHeight;
    });

    doc.save(`${title.replace(/\s+/g, '_')}.pdf`);
};

export const downloadQuizPDF = (quiz: Quiz, format: 'student' | 'teacher' | 'result', userAnswers?: Record<string, string>) => {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();
    const margin = 15;
    let y = 20;
    const pageWidth = doc.internal.pageSize.getWidth();
    const contentWidth = pageWidth - (margin * 2);
    const pageHeight = doc.internal.pageSize.getHeight();

    const addNewPageIfNeeded = (heightNeeded: number = 20) => {
        if (y + heightNeeded > pageHeight - margin) {
            doc.addPage();
            y = 20;
        }
    };

    // Header
    doc.setFontSize(18);
    doc.setFont("helvetica", "bold");
    doc.text(quiz.title, margin, y);
    y += 10;

    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(100);
    let sub = `Generated by StudyGenius AI • ${format === 'student' ? 'Student Copy' : format === 'teacher' ? 'Teacher Key' : 'Results Report'}`;
    if (quiz.topic) sub += ` • Topic: ${quiz.topic}`;
    doc.text(sub, margin, y);
    y += 15;

    if (format === 'result' && quiz.score !== undefined) {
        doc.setFontSize(14);
        doc.setTextColor(0);
        doc.text(`Final Score: ${quiz.score} / ${quiz.questions.length}`, margin, y);
        y += 15;
    }

    // Questions
    quiz.questions.forEach((q, i) => {
        addNewPageIfNeeded(40); 

        doc.setFontSize(11);
        doc.setTextColor(0);
        doc.setFont("helvetica", "bold");
        const qText = `${i + 1}. ${q.text}`;
        const splitQ = doc.splitTextToSize(qText, contentWidth);
        doc.text(splitQ, margin, y);
        y += (splitQ.length * 6) + 4;

        doc.setFont("helvetica", "normal");
        doc.setFontSize(10);

        q.options.forEach((opt, index) => {
            addNewPageIfNeeded(10);

            // Use standard ASCII letters instead of Unicode symbols to prevent rendering issues
            const letter = String.fromCharCode(65 + index); // A, B, C...
            let prefix = `${letter}.`; 
            let optColor = [60, 60, 60]; // Default gray

            if (format === 'teacher') {
                if (opt === q.correctAnswer) {
                    prefix = `${letter}. (Correct)`;
                    doc.setFont("helvetica", "bold");
                    optColor = [0, 128, 0]; // Green
                } else {
                    doc.setFont("helvetica", "normal");
                }
            } else if (format === 'result' && userAnswers) {
                const userAnswer = userAnswers[q.id];
                // Reset font default
                doc.setFont("helvetica", "normal");

                if (opt === q.correctAnswer) {
                    prefix = `${letter}. (Correct)`;
                    optColor = [0, 128, 0]; // Green

                    if (opt === userAnswer) {
                        doc.setFont("helvetica", "bold"); // Bold if user got it right
                        prefix = `${letter}. (Your Answer - Correct)`;
                    }
                } else if (opt === userAnswer) {
                    // User selected wrong answer
                    prefix = `${letter}. (Your Answer)`;
                    optColor = [200, 0, 0]; // Red
                    doc.setFont("helvetica", "bold");
                }
            }
            // Student mode defaults to "A. Option" (Black/Gray) with no indicators

            doc.setTextColor(optColor[0], optColor[1], optColor[2]);
            const optText = `${prefix} ${opt}`;
            const splitOpt = doc.splitTextToSize(optText, contentWidth - 5);
            doc.text(splitOpt, margin + 5, y);
            y += (splitOpt.length * 5) + 2;
        });

        // Explanations
        if (format !== 'student') {
            addNewPageIfNeeded(20);
            y += 2;
            doc.setFillColor(245, 247, 250);
            const explLines = doc.splitTextToSize(q.explanation, contentWidth - 10);
            const boxHeight = 15 + (explLines.length * 4);

            // Ensure box fits on page
            if (y + boxHeight > pageHeight - margin) {
                doc.addPage();
                y = 20;
            }

            doc.roundedRect(margin, y, contentWidth, boxHeight, 2, 2, 'F');

            doc.setTextColor(80);
            doc.setFontSize(9);
            doc.setFont("helvetica", "italic");
            doc.text("Explanation:", margin + 3, y + 6);

            doc.setTextColor(50);
            doc.setFont("helvetica", "normal");
            doc.text(explLines, margin + 3, y + 11);

            y += boxHeight + 5;
        } else {
            y += 8;
        }
    });

    const suffix = format === 'student' ? 'test' : format === 'teacher' ? 'key' : 'results';
    doc.save(`${quiz.title.replace(/\s+/g, '_')}_${suffix}.pdf`);
};

export const generateFlashcardsPDF = (title: string, cards: Flashcard[]) => {
    const { jsPDF } = window.jspdf;
