export const downloadAnkiCSV = (title: string, cards: Flashcard[]) => {
    const csvContent = cards.map(c => {
        const front = c.front.replace(/"/g, '""');
        const back = c.back.replace(/"/g, '""');
        return `"${front}","${back}"`;
    }).join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    window.saveAs(blob, `${title.replace(/\s+/g, '_')}_anki.csv`);
};

export const downloadBulkZip = async (files: { filename: string, content: string | Blob }[], zipName: string) => {
    if (!window.JSZip) {
        console.error("JSZip not loaded");
        return;
    }
    const zip = new window.JSZip();

    files.forEach(f => {
        zip.file(f.filename, f.content);
    });

    const content = await zip.generateAsync({ type: "blob" });
    window.saveAs(content, `${zipName}.zip`);
};

