import React, { useState, useEffect, useRef } from 'react';
import { Quiz } from '../types';
import { Button, Card, Header } from '../components/UI';
import { extractTextFromFile, downloadQuizPDF } from '../services/fileService';
import { generateQuizFromText, discoverTopics } from '../services/geminiService';
import { saveHistoryItem } from '../services/storageService';
import { Upload, CheckCircle, XCircle, Download, Save, ArrowRight, Settings, AlertCircle, Mic, Volume2, Square, Loader2, ListChecks, FileText, Clock, Play, Pause, RotateCcw } from 'lucide-react';

interface Props {
  onBack: () => void;
  initialData?: Quiz | null;
}

export const QuizGenerator: React.FC<Props> = ({ onBack, initialData }) => {
  const [step, setStep] = useState<'upload' | 'generating' | 'taking' | 'results'>('upload');
  const [file, setFile] = useState<File | null>(null);
  const [extractedText, setExtractedText] = useState<string>("");
  const [isAnalyzingTopics, setIsAnalyzingTopics] = useState(false);

  // Configuration State
  const [questionCount, setQuestionCount] = useState<number>(5);
  const [difficulty, setDifficulty] = useState<string>('Medium');
  const [topic, setTopic] = useState<string>(''); // Manual override
  const [explanationDepth, setExplanationDepth] = useState<string>('Simple');

  // Timer Config State
  const [timerMode, setTimerMode] = useState<'off' | 'question' | 'quiz'>('off');
  const [timePerQuestion, setTimePerQuestion] = useState<number>(30); // seconds
  const [totalQuizTime, setTotalQuizTime] = useState<number>(10); // minutes

  // Topic Discovery State
  const [discoveredTopics, setDiscoveredTopics] = useState<string[]>([]);
  const [selectedTopics, setSelectedTopics] = useState<string[]>([]);

  const [quizData, setQuizData] = useState<Quiz | null>(null);
  const [userAnswers, setUserAnswers] = useState<Record<string, string>>({});
  const [error, setError] = useState<string | null>(null);

  // Quiz Logic State
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0); // For 'question' mode
  const [timeLeft, setTimeLeft] = useState<number>(0); // For active timer
  const [isTimerRunning, setIsTimerRunning] = useState(false);

  // Voice Interaction State
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [listeningId, setListeningId] = useState<string | null>(null);
  const recognitionRef = useRef<any>(null);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
      if (initialData) {
          setQuizData(initialData);
          if (initialData.userAnswers) {
              setUserAnswers(initialData.userAnswers);
          }
          // If score exists, assume completed
          setStep(initialData.score !== undefined ? 'results' : 'taking');
      }
  }, [initialData]);

  // Timer Logic
  useEffect(() => {
      if (step === 'taking' && isTimerRunning && timeLeft > 0) {
          timerRef.current = setTimeout(() => {
              setTimeLeft(prev => prev - 1);
          }, 1000);
      } else if (step === 'taking' && isTimerRunning && timeLeft === 0) {
          handleTimerExpiry();
      }
      return () => {
          if (timerRef.current) clearTimeout(timerRef.current);
      };
  }, [step, isTimerRunning, timeLeft]);

  // Initialize Timer when starting quiz
  const startQuizTimer = (quiz: Quiz) => {
      if (quiz.timerMode === 'question') {
          setTimeLeft(quiz.timeLimitPerQuestion || 30);
      } else if (quiz.timerMode === 'quiz') {
          setTimeLeft((quiz.totalTimeLimit || 10) * 60);
      }
      setIsTimerRunning(true);
  };

  const handleTimerExpiry = () => {
      if (timerMode === 'question') {
          // Move to next question
          if (currentQuestionIndex < (quizData?.questions.length || 0) - 1) {
              setCurrentQuestionIndex(prev => prev + 1);
              setTimeLeft(timePerQuestion); // Reset for next question
          } else {
              handleSubmit(); // End of quiz
          }
      } else if (timerMode === 'quiz') {
          handleSubmit(); // End of total time
          alert("Time's up! Submitting quiz.");
      }
  };

  useEffect(() => {
    // Cleanup speech synthesis on unmount
    return () => {
      window.speechSynthesis.cancel();
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
    };
  }, []);

  // --- Voice Logic ---

  const handleSpeak = (text: string, id: string) => {
    if (speakingId === id) {
      window.speechSynthesis.cancel();
      setSpeakingId(null);
      return;
    }

    window.speechSynthesis.cancel();
    setSpeakingId(id);

    const utterance = new SpeechSynthesisUtterance(text);
    utterance.onend = () => setSpeakingId(null);
    utterance.onerror = () => setSpeakingId(null);
    window.speechSynthesis.speak(utterance);
  };

  const handleListen = (questionId: string, options: string[]) => {
    if (listeningId === questionId) {
        if (recognitionRef.current) recognitionRef.current.stop();
        setListeningId(null);
        return;
    }

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
        alert("Your browser does not support voice recognition.");
        return;
    }

    if (recognitionRef.current) {
        try { recognitionRef.current.stop(); } catch (e) { /* ignore */ }
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.interimResults = true; 
    recognition.maxAlternatives = 1;

    recognition.onstart = () => setListeningId(questionId);

    recognition.onresult = (event: any) => {
        let transcript = '';
        let isFinal = false;

        for (let i = event.resultIndex; i < event.results.length; ++i) {
            if (event.results[i] && event.results[i][0]) {
                transcript += event.results[i][0].transcript;
                if (event.results[i].isFinal) isFinal = true;
            }
        }

        transcript = transcript.toLowerCase().trim();
        if (!transcript) return;

        let matchedOption: string | null = null;
        const hasWord = (text: string, word: string) => new RegExp(`\\b${word}\\b`).test(text);

        const isCommand = (trigger: string, num: string, wordNum: string) => {
             if (transcript === trigger || transcript === num) return true;
             if (hasWord(transcript, `option ${trigger}`)) return true;
             if (hasWord(transcript, `option ${num}`)) return true;
             if (hasWord(transcript, `option ${wordNum}`)) return true;
             return false;
        };

        if (isCommand('a', '1', 'one')) matchedOption = options[0];
        else if (isCommand('b', '2', 'two')) matchedOption = options[1];
        else if (isCommand('c', '3', 'three')) matchedOption = options[2];
        else if (isCommand('d', '4', 'four')) matchedOption = options[3];

        if (!matchedOption) {
            const found = options.find(opt => {
                 const lowerOpt = opt.toLowerCase();
                 if (transcript.includes(lowerOpt) && lowerOpt.length > 3) return true;
                 if (isFinal && lowerOpt.includes(transcript) && transcript.length > 3) return true;
                 return false;
            });
            if (found) matchedOption = found;
        }

        if (matchedOption) {
            recognition.stop(); 
            handleOptionSelect(questionId, matchedOption);
            setListeningId(null);
        }
    };

    recognition.onerror = (event: any) => {
        if (event.error !== 'no-speech' && event.error !== 'aborted') {
            console.error("Speech error", event.error);
        }
        if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
             setListeningId(null);
             alert("Microphone access denied.");
        }
    };

    recognition.onend = () => {
         setTimeout(() => {
             setListeningId((current) => current === questionId ? null : current);
         }, 100);
    };

    recognitionRef.current = recognition;
    try { recognition.start(); } catch (e) { console.error("Failed to start recognition", e); setListeningId(null); }
  };


  // --- Step 1: Upload & Config ---
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setError(null);
      setDiscoveredTopics([]);
      setSelectedTopics([]);

      setIsAnalyzingTopics(true);
      try {
          const text = await extractTextFromFile(selectedFile);
          setExtractedText(text);
          const topics = await discoverTopics(text);
          setDiscoveredTopics(topics);
          setSelectedTopics(topics); 
      } catch (err: any) {
          console.error("File processing error:", err);
          setError("Failed to read file text. Please try again.");
      } finally {
          setIsAnalyzingTopics(false);
      }
    }
  };

  const toggleTopic = (topicName: string) => {
      setSelectedTopics(prev => {
          if (prev.includes(topicName)) {
              return prev.filter(t => t !== topicName);
          } else {
              return [...prev, topicName];
          }
      });
  };

  const handleSelectAllTopics = () => {
      if (selectedTopics.length === discoveredTopics.length) {
          setSelectedTopics([]);
      } else {
          setSelectedTopics(discoveredTopics);
      }
  };

  const handleGenerate = async () => {
    if (!file || !extractedText) {
        setError("Please upload a document first.");
        return;
    }

    setStep('generating');
    setError(null);
    try {
      const finalTopics = selectedTopics.length > 0 && selectedTopics.length < discoveredTopics.length 
        ? selectedTopics 
        : []; 

      const generatedData = await generateQuizFromText(
          extractedText, 
          questionCount, 
          difficulty, 
          topic, 
          explanationDepth,
          finalTopics
      ); 

      const newQuiz: Quiz = {
        id: crypto.randomUUID(),
        title: `${file.name} - Quiz`,
        sourceFileName: file.name,
        createdAt: Date.now(),
        questions: generatedData.questions,
        difficulty,
        topic: finalTopics.length > 0 ? 'Selected Chapters' : topic, 
        selectedTopics: finalTopics,
        explanationDepth,
        timerMode,
        timeLimitPerQuestion: timerMode === 'question' ? timePerQuestion : undefined,
        totalTimeLimit: timerMode === 'quiz' ? totalQuizTime : undefined
      };
      setQuizData(newQuiz);

      // Start Logic
      setCurrentQuestionIndex(0);
      startQuizTimer(newQuiz);

      setStep('taking');
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to generate quiz. Please try another file.");
      setStep('upload');
    }
  };

  // --- Step 2: Taking Quiz ---
  const handleOptionSelect = (questionId: string, option: string) => {
    setUserAnswers(prev => ({ ...prev, [questionId]: option }));
  };

  const handleNextQuestion = () => {
      if (currentQuestionIndex < (quizData?.questions.length || 0) - 1) {
          setCurrentQuestionIndex(prev => prev + 1);
          if (timerMode === 'question') setTimeLeft(timePerQuestion);
      } else {
          handleSubmit();
      }
  };

  const handleSubmit = () => {
    window.speechSynthesis.cancel();
    if (recognitionRef.current) recognitionRef.current.stop();
    setIsTimerRunning(false);
    setStep('results');
  };

  // --- Step 3: Results ---
  const calculateScore = () => {
    if (!quizData) return 0;
    let correct = 0;
    quizData.questions.forEach(q => {
      if (userAnswers[q.id] === q.correctAnswer) correct++;
    });
    return correct;
  };

  const handleSave = () => {
    if (quizData) {
        const score = calculateScore();
        saveHistoryItem({
            id: quizData.id,
            type: 'quiz',
            title: quizData.title,
            date: Date.now(),
            data: { ...quizData, score, userAnswers }
        });
        alert("Quiz saved to History!");
    }
  };

  // Export Handler
  const handleExport = (type: 'student' | 'teacher' | 'result') => {
      if (!quizData) return;
      // We ignore 'type' here as we capture the current visual state
      downloadQuizPDF(quizData, type, type === 'result' ? userAnswers : undefined);
  };

  const formatTime = (seconds: number) => {
      const m = Math.floor(seconds / 60);
      const s = seconds % 60;
      return `${m}:${s.toString().padStart(2, '0')}`;
  };

  // Renderers
  if (step === 'upload' || step === 'generating') {
    return (
      <div className="max-w-5xl mx-auto px-4 py-12">
        <Header title="Create New Quiz" onBack={onBack} />

        <div className="grid md:grid-cols-12 gap-8">
            {/* Left Column: File Upload */}
            <div className="md:col-span-7 space-y-6">
                <Card className="p-8 text-center border-2 border-dashed border-slate-300 bg-slate-50 flex flex-col justify-center items-center min-h-[300px]">
                    <div className="bg-white p-4 rounded-full shadow-sm mb-4">
                    <Upload className="h-8 w-8 text-indigo-600" />
                    </div>
                    <h3 className="text-lg font-semibold mb-2">Upload Document</h3>
                    <p className="text-slate-500 mb-6 max-w-xs mx-auto">Support for PDF and Text files. We'll analyze the structure to help you focus.</p>

                    <input 
                        type="file" 
                        id="file-upload" 
                        className="hidden" 
                        accept=".pdf,.txt,.md" 
                        onChange={handleFileChange}
                    />

                    {!file ? (
                    <label 
                        htmlFor="file-upload" 
                        className="cursor-pointer bg-white border border-slate-300 text-slate-700 px-6 py-2 rounded-lg hover:bg-slate-50 font-medium transition-colors"
                    >
                        Select File
                    </label>
                    ) : (
                    <div className="flex flex-col items-center animate-in fade-in zoom-in duration-300 w-full">
                        <span className="font-medium text-slate-900 mb-4 bg-indigo-50 px-4 py-2 rounded-lg border border-indigo-100 break-all max-w-sm text-center">
                            {file.name}
                        </span>
                        <Button 
                            onClick={() => { setFile(null); setExtractedText(""); setDiscoveredTopics([]); }} 
                            variant="outline"
                            disabled={step === 'generating'}
                            className="text-sm"
                        >
                            Change File
                        </Button>
                    </div>
                    )}
                </Card>

                {/* Detected Topics Panel */}
                {(isAnalyzingTopics || discoveredTopics.length > 0) && (
                    <Card className="p-6 border border-slate-200 bg-white animate-in fade-in slide-in-from-bottom-4">
                        <div className="flex items-center justify-between mb-4">
                            <div className="flex items-center text-slate-900">
                                <ListChecks className="h-5 w-5 mr-2 text-indigo-600" />
                                <h3 className="font-bold">Detected Chapters/Topics</h3>
                            </div>
                            {discoveredTopics.length > 0 && (
                                <button 
                                    onClick={handleSelectAllTopics} 
                                    className="text-xs text-indigo-600 hover:text-indigo-800 font-medium"
                                >
                                    {selectedTopics.length === discoveredTopics.length ? 'Deselect All' : 'Select All'}
                                </button>
                            )}
                        </div>

                        {isAnalyzingTopics ? (
                            <div className="flex items-center justify-center py-8 text-slate-500 text-sm">
                                <Loader2 className="h-5 w-5 animate-spin mr-2" />
                                Analyzing document structure...
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                                {discoveredTopics.map((t, i) => (
                                    <label key={i} className={`flex items-start p-3 rounded-lg border cursor-pointer transition-all ${selectedTopics.includes(t) ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-slate-100 hover:border-slate-300'}`}>
                                        <input 
                                            type="checkbox" 
                                            checked={selectedTopics.includes(t)}
                                            onChange={() => toggleTopic(t)}
                                            className="mt-1 h-4 w-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500"
                                        />
                                        <span className="ml-2 text-sm text-slate-700">{t}</span>
                                    </label>
                                ))}
                            </div>
                        )}
                        {discoveredTopics.length === 0 && !isAnalyzingTopics && extractedText && (
                            <p className="text-sm text-slate-400 text-center py-4">
                                No specific chapters detected. The quiz will cover the entire document.
                            </p>
                        )}
                    </Card>
                )}
            </div>

            {/* Right Column: Configuration */}
            <div className="md:col-span-5">
                <Card className="p-6 h-full border border-slate-200">
                    <div className="flex items-center mb-4 text-slate-900">
                        <Settings className="h-5 w-5 mr-2 text-indigo-600" />
                        <h3 className="font-bold">Quiz Configuration</h3>
                    </div>

                    <div className="space-y-5">
                        {/* Number of Questions */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">
                                Number of Questions
                            </label>
                            <input 
                                type="number" 
                                min={1} 
                                max={20} 
                                value={questionCount}
                                onChange={(e) => setQuestionCount(Number(e.target.value))}
                                className="w-full rounded-md border-slate-300 border px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 text-slate-900"
                            />
                        </div>

                        {/* Difficulty */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">
                                Difficulty Level
                            </label>
                            <div className="grid grid-cols-3 gap-2">
                                {['Easy', 'Medium', 'Hard'].map((level) => (
                                    <button
                                        key={level}
                                        onClick={() => setDifficulty(level)}
                                        className={`text-xs font-medium py-2 rounded border transition-colors ${
                                            difficulty === level 
                                            ? 'bg-indigo-600 text-white border-indigo-600' 
                                            : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
                                        }`}
                                    >
                                        {level}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Explanation Depth */}
                        <div>
                             <label className="block text-sm font-medium text-slate-700 mb-1">
                                 Explanation Depth
                             </label>
                             <select
                                value={explanationDepth}
                                onChange={(e) => setExplanationDepth(e.target.value)}
                                className="w-full rounded-md border-slate-300 border px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 text-slate-900 bg-white text-sm"
                             >
                                <option value="Simple">Simple (Concise)</option>
                                <option value="Detailed">Detailed (In-depth)</option>
                                <option value="Step-by-step">Step-by-step (Logical)</option>
                                <option value="Story">Story (Mnemonic)</option>
                             </select>
                        </div>

                        {/* Timer Mode */}
                        <div>
                             <label className="block text-sm font-medium text-slate-700 mb-1">
                                 Exam Mode (Timer)
                             </label>
                             <select
                                value={timerMode}
                                onChange={(e) => setTimerMode(e.target.value as any)}
                                className="w-full rounded-md border-slate-300 border px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 text-slate-900 bg-white text-sm"
                             >
                                <option value="off">Untimed Practice</option>
                                <option value="question">Timer per Question</option>
                                <option value="quiz">Timer for Entire Quiz</option>
                             </select>
                        </div>

                        {/* Timer Duration Fields */}
                        {timerMode === 'question' && (
                            <div className="animate-in fade-in slide-in-from-top-1">
                                <label className="block text-sm font-medium text-slate-700 mb-1">
                                    Time per Question (seconds)
                                </label>
                                <div className="flex gap-2">
                                    {[30, 45, 60].map(sec => (
                                        <button
                                            key={sec}
                                            onClick={() => setTimePerQuestion(sec)}
                                            className={`flex-1 py-1 text-xs border rounded ${timePerQuestion === sec ? 'bg-indigo-100 border-indigo-300 text-indigo-700' : 'bg-white text-slate-600'}`}
                                        >
                                            {sec}s
                                        </button>
                                    ))}
                                    <input 
                                        type="number" 
                                        value={timePerQuestion}
                                        onChange={(e) => setTimePerQuestion(Number(e.target.value))}
                                        className="w-16 text-center border rounded text-sm"
                                    />
                                </div>
                            </div>
                        )}

                        {timerMode === 'quiz' && (
                            <div className="animate-in fade-in slide-in-from-top-1">
                                <label className="block text-sm font-medium text-slate-700 mb-1">
                                    Total Quiz Time (minutes)
                                </label>
                                <div className="flex gap-2">
                                    {[10, 20, 30].map(min => (
                                        <button
                                            key={min}
                                            onClick={() => setTotalQuizTime(min)}
                                            className={`flex-1 py-1 text-xs border rounded ${totalQuizTime === min ? 'bg-indigo-100 border-indigo-300 text-indigo-700' : 'bg-white text-slate-600'}`}
                                        >
                                            {min}m
                                        </button>
                                    ))}
                                    <input 
                                        type="number" 
                                        value={totalQuizTime}
                                        onChange={(e) => setTotalQuizTime(Number(e.target.value))}
                                        className="w-16 text-center border rounded text-sm"
                                    />
                                </div>
                            </div>
                        )}

                        {/* Specific Topic (Manual Override) */}
                        {discoveredTopics.length === 0 && (
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">
                                    Specific Focus Topic <span className="text-slate-400 font-normal">(Optional)</span>
                                </label>
                                <input 
                                    type="text" 
                                    placeholder="e.g. Historical Dates..."
                                    value={topic}
                                    onChange={(e) => setTopic(e.target.value)}
                                    className="w-full rounded-md border-slate-300 border px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                                />
                            </div>
                        )}

                        {/* Dynamic Button Text */}
                        <div className="mt-8 pt-4 border-t border-slate-100">
                             <Button 
                                onClick={handleGenerate} 
                                isLoading={step === 'generating'}
                                className="w-full justify-center"
                                icon={!step ? <ArrowRight className="h-4 w-4" /> : undefined}
                                disabled={!file || isAnalyzingTopics}
                            >
                                {step === 'generating' ? 'Generating...' : 
                                 selectedTopics.length > 0 && selectedTopics.length < discoveredTopics.length 
                                 ? `Generate Chapter Quiz (${selectedTopics.length})` 
                                 : 'Generate Full Quiz'}
                            </Button>

                            {error && (
                                 <div className="mt-3 flex items-start text-red-500 text-xs">
                                    <AlertCircle className="h-4 w-4 mr-1 flex-shrink-0 mt-0.5" />
                                    <span>{error}</span>
                                 </div>
                            )}
                        </div>
                    </div>
                </Card>
            </div>
        </div>
      </div>
    );
  }

  if (step === 'taking' || step === 'results') {
    const isResults = step === 'results';
    const score = calculateScore();
    const total = quizData?.questions.length || 0;
    const percentage = Math.round((score / total) * 100);

    // Filter visible questions based on timer mode (single vs list)
    const questionsToShow = (timerMode === 'question' && !isResults)
        ? [quizData?.questions[currentQuestionIndex]!] 
        : quizData?.questions || [];

    return (
      <div className="max-w-3xl mx-auto px-4 py-8 pb-24 relative">
        <div className="flex items-center justify-between mb-8 sticky top-20 z-30 bg-slate-50/90 backdrop-blur py-2">
            <div>
                <Header title={quizData?.title || "Quiz"} onBack={onBack} />
                {/* Metadata Badges */}
                <div className="flex flex-wrap gap-2 mt-[-1.5rem] mb-4">
                    {quizData?.difficulty && (
                        <span className="px-2 py-1 bg-slate-100 text-slate-600 text-xs rounded font-medium border border-slate-200">
                            {quizData.difficulty}
                        </span>
                    )}
                    {timerMode !== 'off' && !isResults && (
                        <div className={`flex items-center px-3 py-1 rounded-full border font-mono text-sm font-bold ${timeLeft < 10 ? 'bg-red-100 text-red-600 border-red-200 animate-pulse' : 'bg-white text-slate-700 border-slate-300'}`}>
                            <Clock className="h-3 w-3 mr-2" />
                            {formatTime(timeLeft)}
                        </div>
                    )}
                </div>
            </div>
            {isResults && (
                <div className="bg-white px-6 py-3 rounded-xl shadow-sm border border-slate-100 text-right">
                    <p className="text-xs text-slate-500 uppercase font-bold tracking-wider">Score</p>
                    <p className={`text-2xl font-bold ${percentage >= 70 ? 'text-emerald-600' : 'text-indigo-600'}`}>
                        {score}/{total}
                    </p>
                </div>
            )}
        </div>

        <div className="space-y-8" id="quiz-capture-area">
          {questionsToShow.map((q, idx) => {
            // Fix index for display if we are showing single question
            const displayIndex = (timerMode === 'question' && !isResults) ? currentQuestionIndex : idx;
            const userAnswer = userAnswers[q.id];
            const isCorrect = userAnswer === q.correctAnswer;
            const isSpeaking = speakingId === q.id;
            const isListening = listeningId === q.id;

            return (
              <Card key={q.id} className={`quiz-card p-6 md:p-8 relative overflow-visible transition-all ${isListening ? 'ring-2 ring-indigo-400 shadow-md' : ''}`}>
                <div className="flex items-start justify-between mb-6">
                   <div className="flex items-start gap-4">
                        <span className="flex-shrink-0 flex items-center justify-center w-8 h-8 rounded-full bg-slate-100 text-slate-500 font-bold text-sm">
                            {displayIndex + 1}
                        </span>
                        <h3 className="text-lg font-medium text-slate-900 leading-relaxed pt-1">{q.text}</h3>
                   </div>

                   {!isResults && (
                       <div className="flex items-center space-x-2 ml-4 flex-shrink-0">
                           {/* TTS Button */}
                           <button 
                               onClick={() => {
                                   const optionsWithLabels = q.options.map((opt, i) => `Option ${i + 1}: ${opt}`).join('. ');
                                   handleSpeak(`${q.text}. ${optionsWithLabels}`, q.id);
                               }}
                               className={`p-2 rounded-full transition-colors ${isSpeaking ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
                               title="Read Aloud"
                           >
                               {isSpeaking ? <Square className="h-4 w-4 fill-current" /> : <Volume2 className="h-4 w-4" />}
                           </button>

                           {/* Voice Answer Button */}
                           <button 
                               onClick={() => handleListen(q.id, q.options)}
                               className={`p-2 rounded-full transition-colors relative ${isListening ? 'bg-red-100 text-red-600 animate-pulse' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
                               title="Answer with Voice"
                           >
                               {isListening ? <Loader2 className="h-4 w-4 animate-spin" /> : <Mic className="h-4 w-4" />}
                           </button>
                       </div>
                   )}
                </div>

                <div className="space-y-3 pl-12">
                  {q.options.map((opt) => {
                    let optionClass = "border-slate-200 hover:bg-slate-50 hover:border-indigo-300";
                    let icon = null;

                    if (isResults) {
                        if (opt === q.correctAnswer) {
                             optionClass = "bg-emerald-50 border-emerald-500 ring-1 ring-emerald-500";
                             icon = <CheckCircle className="h-5 w-5 text-emerald-500 absolute right-4 top-3" />;
                        } else if (opt === userAnswer && userAnswer !== q.correctAnswer) {
                             optionClass = "bg-red-50 border-red-500 ring-1 ring-red-500";
                             icon = <XCircle className="h-5 w-5 text-red-500 absolute right-4 top-3" />;
                        } else {
                             optionClass = "opacity-60 grayscale border-slate-100";
                        }
                    } else {
                        if (userAnswer === opt) {
                            optionClass = "bg-indigo-50 border-indigo-600 ring-1 ring-indigo-600";
                        }
                    }

                    return (
                      <div 
                        key={opt}
                        onClick={() => !isResults && handleOptionSelect(q.id, opt)}
                        className={`relative p-4 rounded-lg border-2 cursor-pointer transition-all duration-200 ${optionClass}`}
                      >
                        <div className="flex items-center">
                            <div className={`w-4 h-4 rounded-full border mr-3 flex items-center justify-center
                                ${userAnswer === opt || (isResults && opt === q.correctAnswer) ? 'border-transparent bg-current' : 'border-slate-300'}
                            `}>
                                <div className="w-1.5 h-1.5 rounded-full bg-white" />
                            </div>
                            <span className="text-slate-800">{opt}</span>
                        </div>
                        {icon}
                      </div>
                    );
                  })}
                </div>

                {/* Listening Feedback */}
                {isListening && (
                    <div className="mt-4 ml-12 text-xs text-indigo-600 font-medium flex items-center">
                        <span className="animate-pulse mr-2">●</span> Listening... Say "Option 1", "A", or the answer text.
                    </div>
                )}

                {isResults && (
                  <div className="mt-6 ml-12 p-4 bg-slate-50 rounded-lg border border-slate-100 text-sm animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-center justify-between mb-1">
                        <p className="font-semibold text-slate-700">Explanation:</p>
                        {quizData?.explanationDepth && <span className="text-xs text-slate-400 uppercase">{quizData.explanationDepth} Style</span>}
                    </div>
                    <p className="text-slate-600 leading-relaxed">{q.explanation}</p>
                  </div>
                )}
              </Card>
            );
          })}
        </div>

        {/* Sticky Footer Action Bar */}
        <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-4 shadow-lg z-50">
            <div className="max-w-3xl mx-auto flex justify-between items-center">
                {!isResults ? (
                    <>
                        <Button variant="outline" onClick={onBack}>Exit</Button>

                        {/* Export Blank Test Button in Taking Mode */}
                        <Button 
                            variant="outline" 
                            className="hidden sm:flex" 
                            onClick={() => handleExport('student')}
                            icon={<FileText className="h-4 w-4" />}
                        >
                            Print Test
                        </Button>

                        {timerMode === 'question' ? (
                            <div className="flex items-center gap-3">
                                <div className="text-sm text-slate-500">
                                    Question {currentQuestionIndex + 1} of {total}
                                </div>
                                <Button 
                                    onClick={handleNextQuestion}
                                    icon={<ArrowRight className="h-4 w-4" />}
                                >
                                    {currentQuestionIndex < total - 1 ? 'Next' : 'Submit'}
                                </Button>
                            </div>
                        ) : (
                            <>
                                <div className="text-sm text-slate-500 hidden sm:block">
                                    {Object.keys(userAnswers).length} of {total} answered
                                </div>
                                <Button 
                                    onClick={handleSubmit} 
                                    disabled={Object.keys(userAnswers).length !== total && timerMode !== 'quiz'}
                                    icon={<ArrowRight className="h-4 w-4" />}
                                >
                                    Submit Quiz
                                </Button>
                            </>
                        )}
                    </>
                ) : (
                    <>
                        <Button 
                            variant="outline" 
                            onClick={handleSave}
                            icon={<Save className="h-4 w-4" />}
                        >
                            Save History
                        </Button>
                        <Button 
                            variant="primary" 
                            onClick={() => handleExport('result')}
                            icon={<Download className="h-4 w-4" />}
                        >
                            Download PDF
                        </Button>
                    </>
                )}
            </div>
        </div>
      </div>
    );
  }

  return null;
};

I will ensure the **Quiz Timer features** are accessible when reloading quizzes from history and integrate the **AI Chat Assistant** into the quiz workflow.

The main issue causing "inaccessible timer features" is that the timer configuration state (`timerMode`, `timeLeft`) wasn't being restored when opening a saved quiz, causing the timer to remain hidden/inactive.

Here are the changes:
1.  **`views/QuizGenerator.tsx`**:
    *   **Fix History Restore**: Updated the `useEffect` to correctly populate `timerMode`, `timePerQuestion`, and `totalQuizTime` from `initialData`. This ensures the timer appears when you open a saved quiz.
    *   **Integrate ChatWidget**: Added the `<ChatWidget />` component so you can ask the AI questions while configuring or taking the quiz.
    *   **Timer Resume**: Added logic to initialize the `timeLeft` and start the timer when resuming an incomplete quiz.

