                    <>
                        <Button 
                            variant="outline" 
                            onClick={handleSave}
                            icon={<Save className="h-4 w-4" />}
                        >
                            Save History
                        </Button>
                        <Button 
                            variant="primary" 
                            onClick={() => handleExport('result')}
                            icon={<Download className="h-4 w-4" />}
                        >
                            Download PDF
                        </Button>
                    </>
                )}
            </div>
        </div>

        <ChatWidget contextType="quiz" contextData={getChatContext()} />
      </div>
    );
  }

  return null;
};

