export const checkWebOriginality = async (text: string): Promise<{ score: number, matches: PlagiarismMatch[] }> => {
    const model = 'gemini-2.5-flash';

    const prompt = `
        Analyze the following text for sentences that appear verbatim on the public web.
        Search for the content. 

        If you find exact matches, list them. 
        If the text seems original or only matches generic phrases, state that.

        Text to analyze:
        ${text.substring(0, 2000)}
    `;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            tools: [{ googleSearch: {} }]
        }
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const matches: PlagiarismMatch[] = [];
    let score = 0;

    if (groundingChunks.length > 0) {
        score = Math.min(100, groundingChunks.length * 10); 
        groundingChunks.forEach((chunk: any) => {
            if (chunk.web?.uri) {
                matches.push({
                    text: chunk.web.title || "Web Match",
                    source: 'web',
                    similarity: 100,
                    url: chunk.web.uri
                });
            }
        });
    }

    return { score, matches };
};

export const generateSmartNotes = async (
    text: string,
    type: NoteType,
    granularity: 'Short' | 'Medium' | 'Long',
    onStreamUpdate?: (text: string) => void
): Promise<string | MindMapNode | ComparisonTable> => {
    const model = 'gemini-2.5-flash';

    let prompt = "";
    let schema: Schema | undefined = undefined;

    const lengthInstruction = {
        'Short': "Concise, high-level overview.",
        'Medium': "Balanced detail covering key points.",
        'Long': "Comprehensive, detailed covering all nuances."
    }[granularity];

    if (type === 'MINDMAP') {
        prompt = `
            Analyze the text and create a hierarchical mind map structure.
            The root should be the main topic of the document.
            Children should be major sections/concepts, with further sub-children for details.
            Limit depth to 3 levels.

            Text: ${text}
        `;
        schema = mindmapSchema;
    } else if (type === 'TABLE') {
        prompt = `
            Analyze the text and identify the main entities or concepts that can be compared.
            Create a comparison table.
            - Title: What is being compared?
            - Headers: Feature/Attribute names (e.g., Concept, Definition, Pros, Cons).
            - Rows: Data for each entity.

            Detail Level: ${lengthInstruction}

            Text: ${text}
        `;
        schema = tableSchema;
    } else if (type === 'FORMULAS') {
        prompt = `
            Extract all mathematical formulas, scientific equations, and key definitions from the text.
            Output Format: Markdown.
            - Group by topic.
            - Use LaTeX syntax for math (wrapped in $ or $$).
            - Provide a brief explanation for variables.

            Text: ${text}
        `;
    } else {
        prompt = `
            Create structured, condensed notes from the text.
            Format: Markdown with clear headings and bullet points.
            Style: ${lengthInstruction}

            Text: ${text}
        `;
    }

    const commonConfig = {
        thinkingConfig: { thinkingBudget: 0 }
    };

    if (!schema && onStreamUpdate) {
         const responseStream = await ai.models.generateContentStream({
            model,
            contents: prompt,
            config: commonConfig
         });

         let fullText = "";
         for await (const chunk of responseStream) {
             const textChunk = chunk.text || "";
             fullText += textChunk;
             onStreamUpdate(fullText);
         }
         return fullText;
    }

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            ...commonConfig,
            ...(schema ? { responseMimeType: "application/json", responseSchema: schema } : {})
        }
    });

    if (schema) {
        const result = JSON.parse(response.text || "{}");
        return type === 'MINDMAP' ? result.root : result;
    }

    return response.text || "Failed to generate notes.";
};

